<?php session_start(); // Configuration $recipient_email = "info@broadsafeservices.com.au"; $sender_email = "noreply@broadsafeservices.com.au"; $subject = "New Job Application - Broadsafe Services"; $max_file_size = 5 * 1024 * 1024; // 5MB $allowed_file_types = ['application/pdf', 'application/msword', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document']; // Security: Check honeypot field if (!empty($_POST['website'])) { // This is likely a bot - silently fail header("Location: /apply-online"); exit; } // Validate form type if (!isset($_POST['form_type']) || $_POST['form_type']!== 'job_application') { $_SESSION['error_message'] = "Invalid form submission."; header("Location: /apply-online"); exit; } // Basic rate limit (60 seconds per session) if (isset($_SESSION['last_application_submit']) && (time - $_SESSION['last_application_submit']) < 60) { $_SESSION['error_message'] = "Please wait a minute before submitting again."; header("Location: /apply-online"); exit; } // Function to sanitize input function sanitize_input($data) { $data = trim($data); $data = stripslashes($data); $data = htmlspecialchars($data, ENT_QUOTES, 'UTF-8'); return $data; } // Function to validate email function validate_email($email) { return filter_var($email, FILTER_VALIDATE_EMAIL); } // Check if form was submitted if ($_SERVER["REQUEST_METHOD"] == "POST") { // Sanitize all input fields $first_name = isset($_POST['first_name'])? sanitize_input($_POST['first_name']): ''; $last_name = isset($_POST['last_name'])? sanitize_input($_POST['last_name']): ''; $email = isset($_POST['email'])? sanitize_input($_POST['email']): ''; $mobile = isset($_POST['mobile'])? sanitize_input($_POST['mobile']): ''; $dob = isset($_POST['dob'])? sanitize_input($_POST['dob']): ''; $gender = isset($_POST['gender'])? sanitize_input($_POST['gender']): ''; $state = isset($_POST['state'])? sanitize_input($_POST['state']): ''; $suburb = isset($_POST['suburb'])? sanitize_input($_POST['suburb']): ''; $postcode = isset($_POST['postcode'])? sanitize_input($_POST['postcode']): ''; $shirt_size = isset($_POST['shirt_size'])? sanitize_input($_POST['shirt_size']): ''; $pant_size = isset($_POST['pant_size'])? sanitize_input($_POST['pant_size']): ''; $height = isset($_POST['height'])? sanitize_input($_POST['height']): ''; $experience_years = isset($_POST['experience_years'])? sanitize_input($_POST['experience_years']): ''; $hobbies = isset($_POST['hobbies'])? sanitize_input($_POST['hobbies']): ''; $sports = isset($_POST['sports'])? sanitize_input($_POST['sports']): ''; $medical_conditions = isset($_POST['medical_conditions'])? sanitize_input($_POST['medical_conditions']): ''; $security_licence = isset($_POST['security_licence'])? sanitize_input($_POST['security_licence']): ''; $first_aid = isset($_POST['first_aid'])? sanitize_input($_POST['first_aid']): ''; $wwcc = isset($_POST['wwcc'])? sanitize_input($_POST['wwcc']): ''; $transportation = isset($_POST['transportation'])? sanitize_input($_POST['transportation']): ''; $working_rights = isset($_POST['working_rights'])? sanitize_input($_POST['working_rights']): ''; $dayshift = isset($_POST['dayshift'])? sanitize_input($_POST['dayshift']): ''; $afternoon_shift = isset($_POST['afternoon_shift'])? sanitize_input($_POST['afternoon_shift']): ''; $night_shift = isset($_POST['night_shift'])? sanitize_input($_POST['night_shift']): ''; $saturday = isset($_POST['saturday'])? sanitize_input($_POST['saturday']): ''; $sunday = isset($_POST['sunday'])? sanitize_input($_POST['sunday']): ''; $not_available = isset($_POST['not_available'])? sanitize_input($_POST['not_available']): ''; $security_experience = isset($_POST['security_experience'])? sanitize_input($_POST['security_experience']): ''; $hear_about_us = isset($_POST['hear_about_us'])? sanitize_input($_POST['hear_about_us']): ''; // Validate required fields $required_fields = [ 'first_name', 'last_name', 'email', 'mobile', 'dob', 'gender', 'state', 'suburb', 'postcode', 'shirt_size', 'pant_size', 'height', 'experience_years', 'medical_conditions', 'security_licence', 'first_aid', 'wwcc', 'transportation', 'working_rights', 'dayshift', 'afternoon_shift', 'night_shift', 'saturday', 'sunday', 'security_experience', 'hear_about_us' ]; foreach ($required_fields as $field) { if (empty($_POST[$field])) { $_SESSION['error_message'] = "Please fill in all required fields."; header("Location: /apply-online"); exit; } } // Validate email if (!validate_email($email)) { $_SESSION['error_message'] = "Please enter a valid email address."; header("Location: /apply-online"); exit; } // Handle file upload $cv_attachment = ''; $cv_filename = ''; if (isset($_FILES['cv']) && $_FILES['cv']['error'] == UPLOAD_ERR_OK) { $file_tmp_name = $_FILES['cv']['tmp_name']; $file_name = $_FILES['cv']['name']; $file_size = $_FILES['cv']['size']; $file_type = $_FILES['cv']['type']; $finfo = new finfo(FILEINFO_MIME_TYPE); $detected_type = $finfo->file($file_tmp_name); $allowed_extensions = [ 'application/pdf' => 'pdf', 'application/msword' => 'doc', 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' => 'docx' ]; // Validate file type if (!in_array($detected_type, $allowed_file_types, true)) { $_SESSION['error_message'] = "Invalid file type. Please upload PDF, DOC, or DOCX files only."; header("Location: /apply-online"); exit; } // Validate file size if ($file_size > $max_file_size) { $_SESSION['error_message'] = "File size must be less than 5MB."; header("Location: /apply-online"); exit; } // Read file content $file_content = file_get_contents($file_tmp_name); $cv_attachment = chunk_split(base64_encode($file_content)); $safe_name = preg_replace('/[^a-zA-Z0-9._-]/', '_', basename($file_name)); $safe_name = trim($safe_name, '._'); if ($safe_name === '') { $safe_name = 'cv-'. date('YmdHis'); } $extension = $allowed_extensions[$detected_type]?? 'bin'; if (!preg_match('/\.'. preg_quote($extension, '/'). '$/i', $safe_name)) { $safe_name.= '.'. $extension; } $cv_filename = $safe_name; } else { $_SESSION['error_message'] = "Please upload your CV."; header("Location: /apply-online"); exit; } // Create email body $email_body = "NEW JOB APPLICATION SUBMISSION\n"; $email_body.= "================================\n\n"; $email_body.= "PERSONAL INFORMATION:\n"; $email_body.= "Full Name: ". $first_name. " ". $last_name. "\n"; $email_body.= "Email: ". $email. "\n"; $email_body.= "Mobile: ". $mobile. "\n"; $email_body.= "Date of Birth: ". $dob. "\n"; $email_body.= "Gender: ". $gender. "\n\n"; $email_body.= "LOCATION INFORMATION:\n"; $email_body.= "State: ". $state. "\n"; $email_body.= "Suburb: ". $suburb. "\n"; $email_body.= "Post Code: ". $postcode. "\n\n"; $email_body.= "UNIFORM & PHYSICAL INFORMATION:\n"; $email_body.= "Shirt Size: ". $shirt_size. "\n"; $email_body.= "Pant Size: ". $pant_size. "\n"; $email_body.= "Height: ". $height. " cm\n\n"; $email_body.= "EXPERIENCE & QUALIFICATIONS:\n"; $email_body.= "Years of Experience: ". $experience_years. "\n"; $email_body.= "Hobbies: ". $hobbies. "\n"; $email_body.= "Sports: ". $sports. "\n"; $email_body.= "Medical Conditions: ". $medical_conditions. "\n"; $email_body.= "Security Licence: ". $security_licence. "\n"; $email_body.= "First Aid Certificate: ". $first_aid. "\n"; $email_body.= "WWCC Card: ". $wwcc. "\n"; $email_body.= "Transportation: ". $transportation. "\n"; $email_body.= "Working Rights: ". $working_rights. "\n\n"; $email_body.= "AVAILABILITY:\n"; $email_body.= "Dayshift (0700-1500): ". $dayshift. "\n"; $email_body.= "Afternoon Shift (1500-Midnight): ". $afternoon_shift. "\n"; $email_body.= "Night Shift (Midnight-0700): ". $night_shift. "\n"; $email_body.= "Saturday: ". $saturday. "\n"; $email_body.= "Sunday: ". $sunday. "\n"; $email_body.= "Not Available: ". $not_available. "\n\n"; $email_body.= "ADDITIONAL INFORMATION:\n"; $email_body.= "Security Experience:\n". $security_experience. "\n\n"; $email_body.= "How did you hear about us: ". $hear_about_us. "\n\n"; $email_body.= "================================\n"; $email_body.= "Submitted on: ". date('Y-m-d H:i:s'). "\n"; $email_body.= "IP Address: ". $_SERVER['REMOTE_ADDR']. "\n"; // Email headers $boundary = md5(time); $headers = "From: ". $sender_email. "\r\n"; $headers.= "Reply-To: ". $email. "\r\n"; $headers.= "MIME-Version: 1.0\r\n"; $headers.= "Content-Type: multipart/mixed; boundary=\"". $boundary. "\"\r\n"; // Email message with attachment $message = "--". $boundary. "\r\n"; $message.= "Content-Type: text/plain; charset=\"UTF-8\"\r\n"; $message.= "Content-Transfer-Encoding: 7bit\r\n\r\n"; $message.= $email_body. "\r\n\r\n"; // Attachment $message.= "--". $boundary. "\r\n"; $message.= "Content-Type: application/octet-stream; name=\"". $cv_filename. "\"\r\n"; $message.= "Content-Transfer-Encoding: base64\r\n"; $message.= "Content-Disposition: attachment; filename=\"". $cv_filename. "\"\r\n\r\n"; $message.= $cv_attachment. "\r\n\r\n"; $message.= "--". $boundary. "--"; // Send email if (mail($recipient_email, $subject, $message, $headers)) { $_SESSION['last_application_submit'] = time; // Also send confirmation to applicant $confirmation_subject = "Application Received - Broadsafe Services"; $confirmation_body = "Dear ". $first_name. ",\n\n"; $confirmation_body.= "Thank you for applying to join the Broadsafe Services Security team.\n\n"; $confirmation_body.= "We have received your application and will review it shortly.\n"; $confirmation_body.= "If your qualifications match our requirements, we will contact you for the next steps.\n\n"; $confirmation_body.= "Best regards,\n"; $confirmation_body.= "Broadsafe Services Recruitment Team\n"; $confirmation_body.= "info@broadsafeservices.com.au\n"; $confirmation_body.= "03 7064 8292"; $confirmation_headers = "From: ". $sender_email. "\r\n"; $confirmation_headers.= "Reply-To: ". $recipient_email. "\r\n"; // Send confirmation email mail($email, $confirmation_subject, $confirmation_body, $confirmation_headers); $_SESSION['success_message'] = "Application submitted successfully! We have sent a confirmation email to you."; header("Location: /apply-online"); exit; } else { $_SESSION['error_message'] = "There was an error submitting your application. Please try again or contact us directly."; header("Location: /apply-online"); exit; } } else { $_SESSION['error_message'] = "Invalid request method."; header("Location: /apply-online"); exit; }?>

